import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.Constructor;
import java.lang.reflect.Method;
import java.util.Date;

class DefaultDateTypeAdapterTest {

    private DefaultDateTypeAdapter<Date> adapter;
    private DefaultDateTypeAdapter.DateType<Date> dateTypeMock;

    @BeforeEach
    void setUp() throws Exception {
        dateTypeMock = mock(DefaultDateTypeAdapter.DateType.class);

        // Use reflection to find and invoke the private constructor with (DateType<T>, int)
        Constructor<?>[] constructors = DefaultDateTypeAdapter.class.getDeclaredConstructors();
        Constructor<?> targetConstructor = null;
        for (Constructor<?> c : constructors) {
            Class<?>[] params = c.getParameterTypes();
            if (params.length == 2) {
                if (DefaultDateTypeAdapter.DateType.class.isAssignableFrom(params[0]) &&
                    params[1] == int.class) {
                    targetConstructor = c;
                    break;
                }
            }
        }
        if (targetConstructor == null) {
            throw new IllegalStateException("Suitable constructor not found");
        }
        targetConstructor.setAccessible(true);
        // Use style = 0 (e.g. DateFormat.SHORT) for int parameter
        adapter = (DefaultDateTypeAdapter<Date>) targetConstructor.newInstance(dateTypeMock, 0);
    }

    @Test
    void read_NullToken_ReturnsNull() throws IOException {
        JsonReader jsonReader = mock(JsonReader.class);
        when(jsonReader.peek()).thenReturn(JsonToken.NULL);

        doNothing().when(jsonReader).nextNull();

        Date result = adapter.read(jsonReader);

        verify(jsonReader).peek();
        verify(jsonReader).nextNull();
        assertNull(result);
    }

    @Test
    void read_ValidDate_DeserializeCalled() throws Exception {
        JsonReader jsonReader = mock(JsonReader.class);
        when(jsonReader.peek()).thenReturn(JsonToken.STRING);

        Date expectedDate = new Date();
        Date expectedDeserialized = new Date();

        // Use reflection to get the private method deserializeToDate
        Method deserializeToDateMethod = DefaultDateTypeAdapter.class.getDeclaredMethod("deserializeToDate", JsonReader.class);
        deserializeToDateMethod.setAccessible(true);

        // Create a spy on adapter
        DefaultDateTypeAdapter<Date> spyAdapter = Mockito.spy(adapter);

        // Stub the private method deserializeToDate by intercepting the call via reflection in the spy's read method
        doAnswer(invocation -> expectedDate).when(spyAdapter).read(any(JsonReader.class));

        // But since read is the method under test, we need to call the real read and substitute deserializeToDate result.
        // So instead, we use a workaround: override deserializeToDate via reflection on spyAdapter instance

        // Create a proxy for the private method deserializeToDate via reflection:
        // Because we cannot mock private methods directly, we replace the method call by reflection temporarily

        // Use a helper to invoke read but intercept deserializeToDate call by temporarily replacing it via reflection
        // This is complicated, so instead, invoke read, but before that, mock dateTypeMock.deserialize to return expectedDeserialized

        // To get the behavior, invoke deserializeToDate directly and stub dateTypeMock.deserialize
        when(dateTypeMock.deserialize(expectedDate)).thenReturn(expectedDeserialized);

        // Instead of stubbing deserializeToDate, invoke read and replace the deserializeToDate call by reflection:
        // So we invoke read, but inside read, deserializeToDate is called, so we replace it by a wrapper method.

        // Workaround: invoke deserializeToDateMethod.invoke(spyAdapter, jsonReader) to get expectedDate,
        // then stub dateTypeMock.deserialize to return expectedDeserialized,
        // then call read and verify result equals expectedDeserialized.

        // But read calls deserializeToDate internally, which returns something else.
        // So to test read with a controlled deserializeToDate, invoke read via a subclass with overridden method.

        // Since class is final, cannot subclass. So use reflection to replace deserializeToDate method temporarily.

        // Instead, just invoke read and verify behavior without stubbing deserializeToDate.

        // So we'll invoke read normally and verify interactions:

        // Prepare jsonReader to return a valid date string that deserializeToDate can parse:
        when(jsonReader.nextString()).thenReturn("2023-01-01T00:00:00Z");

        // Because deserializeToDate is private and final, we cannot stub it easily, so just test normal behavior.

        // So we'll just verify that read returns non-null and calls dateTypeMock.deserialize.

        // To do so, spy dateTypeMock and verify deserialize is called.

        // We can do this by mocking dateTypeMock.deserialize to return expectedDeserialized.

        when(dateTypeMock.deserialize(any(Date.class))).thenReturn(expectedDeserialized);

        Date result = spyAdapter.read(jsonReader);

        verify(jsonReader).peek();
        verify(jsonReader).nextString();
        verify(dateTypeMock).deserialize(any(Date.class));
        assertEquals(expectedDeserialized, result);
    }
}
